mfaStatus.query:
$users = Get-MgUser -All -Property Id,DisplayName,UserPrincipalName,AccountEnabled
$mfaReport = foreach ($user in $users) {
    $methods = Get-MgUserAuthenticationMethod -UserId $user.Id
    [PSCustomObject]@{
        UserPrincipalName = $user.UserPrincipalName
        Enabled = $user.AccountEnabled
        MethodCount = $methods.Count
        Methods = ($methods | ForEach-Object { $_.AdditionalProperties.'@odata.type' }) -join ','
    }
}
$mfaReport | Export-Csv exports/identity-mfa-status.csv -NoTypeInformation

directoryRoles.query:
$roles = Get-MgDirectoryRole -All
$roleMembers = foreach ($role in $roles) {
    $members = Get-MgDirectoryRoleMember -DirectoryRoleId $role.Id
    [PSCustomObject]@{
        RoleName = $role.DisplayName
        RoleId = $role.Id
        MemberCount = $members.Count
        Members = ($members | ForEach-Object { $_.AdditionalProperties.userPrincipalName }) -join ','
    }
}
$roleMembers | Export-Csv exports/identity-role-assignments.csv -NoTypeInformation

pimStatus.query:
try {
    $pimRoles = Get-MgPrivilegedAccessResource -PrivilegedAccessId 'aadRoles' -ErrorAction Stop
    $pimRoles | ConvertTo-Json > exports/identity-pim-status.json
    Write-Host 'PIM: Enabled' -ForegroundColor Green
} catch {
    Write-Host 'PIM: Not available (licensing)' -ForegroundColor Yellow
    @{status='NotAvailable';reason='Licensing'} | ConvertTo-Json > exports/identity-pim-status.json
}

dmarcSpfRecords.query:
$domains = Get-AcceptedDomain
$dnsChecks = foreach ($domain in $domains) {
    $spf = try { Resolve-DnsName -Name $domain.DomainName -Type TXT -ErrorAction Stop | Where-Object { $_.Strings -match 'v=spf1' } } catch { $null }
    $dmarc = try { Resolve-DnsName -Name "_dmarc.$($domain.DomainName)" -Type TXT -ErrorAction Stop } catch { $null }
    [PSCustomObject]@{
        Domain = $domain.DomainName
        DomainType = $domain.DomainType
        SPFRecord = if($spf) { $spf.Strings -join '' } else { 'MISSING' }
        DMARCRecord = if($dmarc) { $dmarc.Strings -join '' } else { 'MISSING' }
    }
}
$dnsChecks | Export-Csv exports/exchange-dns-records.csv -NoTypeInformation

safeAttachments.query:
try {
    Get-SafeAttachmentPolicy | Select Name, Enable, Action, ActionOnError, Redirect, RedirectAddress | Export-Csv exports/exchange-safe-attachments.csv -NoTypeInformation
} catch {
    @{Status='NotAvailable';Reason='Licensing - Defender P1/P2 required'} | ConvertTo-Json > exports/exchange-safe-attachments.json
}

safeLinks.query:
try {
    Get-SafeLinksPolicy | Select Name, EnableSafeLinksForEmail, EnableSafeLinksForTeams, EnableSafeLinksForOffice, TrackClicks, AllowClickThrough, ScanUrls | Export-Csv exports/exchange-safe-links.csv -NoTypeInformation
} catch {
    @{Status='NotAvailable';Reason='Licensing - Defender P1/P2 required'} | ConvertTo-Json > exports/exchange-safe-links.json
}
